custom_code.css:
.flex__container{
display: flex;
align-items: center;
}

.flex__container > .element__wrapper--full-width{
margin: 0;
}

.flex__container--delete{
margin-left: auto
}

.repeat__container {
    max-height:600px;
    height: 100vh;
    overflow: scroll;
}

.round-image > .ab-image{
border-radius: 50%;
width: 75px;
height: 75px;
overflow: hidden;
}

.round-image > .ab-image > .ab-image__img{
width: 100%;
height: 100%;
object-fit: cover;
}
